import java.io.*;import java.util.*;class Main{static int[] smallestRange(List<int[]> nums){PriorityQueue<int[]> pq=new PriorityQueue<>(Comparator.comparingInt(a->a[0]));int currentMax=Integer.MIN_VALUE;for(int i=0;i<nums.size();i++){pq.offer(new int[]{nums.get(i)[0],i,0});currentMax=Math.max(currentMax,nums.get(i)[0]);}int bestL=pq.peek()[0],bestR=currentMax;while(true){int[] cur=pq.poll();if(currentMax-cur[0]<bestR-bestL||currentMax-cur[0]==bestR-bestL&&cur[0]<bestL){bestL=cur[0];bestR=currentMax;}if(cur[2]+1==nums.get(cur[1]).length)return new int[]{bestL,bestR};int nv=nums.get(cur[1])[cur[2]+1];pq.offer(new int[]{nv,cur[1],cur[2]+1});currentMax=Math.max(currentMax,nv);}}public static void main(String[] a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int k=Integer.parseInt(d[idx++]);ArrayList<int[]> nums=new ArrayList<>();for(int i=0;i<k;i++){int n=Integer.parseInt(d[idx++]);int[] row=new int[n];for(int j=0;j<n;j++)row[j]=Integer.parseInt(d[idx++]);nums.add(row);}int[] ans=smallestRange(nums);if(tc>0)out.append("\n\n");out.append("[").append(ans[0]).append(",").append(ans[1]).append("]");}System.out.print(out);}}
